#define BIGRND 0x7fffffff
#define ETA 0.3f
#define MOMENTUM 0.3f
#define WIDTH 16
#define HEIGHT 16
#define BLOCK_SIZE 16

#define ABS(x) ((x) > 0.0f ? (x) : -(x))

float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

__kernel void bpnn_layerforward_ocl(__global float *l1,
                                    __global float *l2,
                                    __global float *conn,
                                    __global float *partial_sum,
                                    __local float *local_conn,
                                    __local float *local_l1,
                                    int n1,
                                    int n2) {
    int j = get_global_id(1);
    int block_idx = get_group_id(0);
    int local_idx = get_local_id(0);
    int local_size = get_local_size(0);

    if (j >= n2 || j < 1) return;

    int conn_cols = n2 + 1;

    // Load input units into local memory
    if (local_idx <= n1) {
        local_l1[local_idx] = l1[local_idx];
    }

    // Load weights into local memory for this block
    int k = block_idx * local_size + local_idx;
    if (k <= n1) {
        local_conn[local_idx * local_size + local_idx] = conn[k * conn_cols + j];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;
    int start_k = block_idx * local_size;
    int end_k = start_k + local_size;

    if (end_k > n1 + 1) end_k = n1 + 1;

    for (int k_local = 0; k_local < local_size; k_local++) {
        int k_global = start_k + k_local;
        if (k_global <= n1) {
            // Use local memory
            sum += local_conn[k_local * local_size + local_idx] * local_l1[k_local];
        }
    }

    // Fix index to match host expectation: block_idx * n2 + (j - 1)
    partial_sum[block_idx * n2 + (j - 1)] = sum;
}

__kernel void bpnn_adjust_weights_ocl(__global float *delta,
                                      int ndelta,
                                      __global float *ly,
                                      int nly,
                                      __global float *w,
                                      __global float *oldw) {
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j < 1 || j > ndelta) return;
    if (k > nly) return;

    int row_size = ndelta + 1;
    float new_dw = (ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k * row_size + j]);

    w[k * row_size + j] += new_dw;
    oldw[k * row_size + j] = new_dw;
}
